'use client';

import Link from "next/link"
import Image from "next/image"
import { social } from "./types/types"
import { useLayout } from "../context/layoutContext"

type DrawerProps = {
    name: string,
    avatar: string,
    social: Array<social>
}

export default function Drawer({ name, avatar, social }: DrawerProps) {
    const { isDrawerOpen, setIsDrawerOpen } = useLayout();

    return (
        <>
            {/* Dark blur backdrop element that closes the panel on layout click-away actions */}
            <div
                className={`custom-obfuscator ${isDrawerOpen ? 'active' : ''}`}
                onClick={() => setIsDrawerOpen(false)}
            />

            {/* Sidebar drawer canvas drawer component frame */}
            <div className={`custom-drawer ${isDrawerOpen ? 'open' : ''}`}>
                <div className="nicescroll-bar">
                    <div className="drawer-profile-wrap p-6 text-center">
                        <Image src={avatar} alt={name} className="candidate-img-drawer mx-auto mt-4 mb-4 rounded-full border-4 border-slate-700" width={120} height={120} />
                        <span className="candidate-name block font-bold text-white text-lg mb-4">{name}</span>
                        <ul className="social-icons flex justify-center gap-3">
                            {social.map(s =>
                                <li key={`${s.id}`}>
                                    <Link className={s.class} href={s.url}>
                                        <i className={`zmdi zmdi-${s.label} text-slate-400 hover:text-white text-xl`}></i>
                                    </Link>
                                </li>
                            )}
                        </ul>
                    </div>

                    <div className="navigation-wrap p-4">
                        <ul className="flex flex-col gap-1">
                            {[
                                { href: "#body", label: "about", icon: "zmdi-border-color" },
                                { href: "#portfolio_sec", label: "what i do", icon: "zmdi-case" },
                                { href: "#experience_sec", label: "experience", icon: "zmdi-time-restore" },
                                { href: "#skills_sec", label: "skills", icon: "zmdi-flash" },
                                { href: "#certs_sec", label: "certifications", icon: "zmdi-badge-check" },
                                { href: "#project_sec", label: "projects", icon: "zmdi-code" },
                                { href: "#contact_sec", label: "contact", icon: "zmdi-email" },
                            ].map((item) => (
                                <li key={item.href}>
                                    <a
                                        className="flex items-center gap-4 px-4 py-3 text-slate-300 hover:bg-slate-800 rounded-lg text-sm capitalize transition-colors"
                                        href={item.href}
                                        onClick={() => setIsDrawerOpen(false)}
                                    >
                                        <i className={`zmdi ${item.icon} text-lg w-6`}></i>
                                        <span>{item.label}</span>
                                    </a>
                                </li>
                            ))}
                        </ul>
                    </div>
                </div>
            </div>
        </>
    );
}